import json

import yaml

from prompty.model import TurnEndPayload


def test_load_json_turnendpayload():
    json_data = r"""
    {
      "iterations": 2,
      "durationMs": 1500
    }
    """
    data = json.loads(json_data, strict=False)
    instance = TurnEndPayload.load(data)
    assert instance is not None
    assert instance.iterations == 2
    assert instance.duration_ms == 1500


def test_load_yaml_turnendpayload():
    yaml_data = r"""
    iterations: 2
    durationMs: 1500

    """
    data = yaml.load(yaml_data, Loader=yaml.FullLoader)
    instance = TurnEndPayload.load(data)
    assert instance is not None
    assert instance.iterations == 2
    assert instance.duration_ms == 1500


def test_roundtrip_json_turnendpayload():
    """Test that load -> save -> load produces equivalent data."""
    json_data = r"""
    {
      "iterations": 2,
      "durationMs": 1500
    }
    """
    original_data = json.loads(json_data, strict=False)
    instance = TurnEndPayload.load(original_data)
    saved_data = instance.save()
    reloaded = TurnEndPayload.load(saved_data)
    assert reloaded is not None
    assert reloaded.iterations == 2
    assert reloaded.duration_ms == 1500


